let r1_: int = r1 as int;
let r2_: int = r2 as int;
let s: Seq<K> = pre_self_@;

// Bring the KeyTrait ordering laws (asymmetry, transitivity, etc.) into context.
K::cmp_properties();

// The insertion index is unique: derive `r1 == r2` by deriving a contradiction
// from `r1 < r2` (and symmetrically `r2 < r1`). The contradiction comes from
// sortedness of post1_self_@ and post2_self_@: both insertions are at a position
// where `k` sits between strictly-smaller and strictly-larger neighbours, so
// only one index is consistent with the strict order on `pre_self_@`.
assert(r1 == r2) by {
    K::cmp_properties();
    if r1_ < r2_ {
        // Structure of post1_self_@ = s.insert(r1_, k):
        //   post1_self_@[r1_]     == k
        //   post1_self_@[r1_ + 1] == s[r1_]    (since r1_ < pre_self_@.len())
        assert(post1_self_@[r1_] == k);
        assert(post1_self_@[r1_ + 1] == s[r1_]);
        assert(0 <= r1_ && r1_ + 1 < post1_self_@.len());
        // Sortedness of post1_self_@ instantiated at (r1_, r1_+1):
        //   k.cmp_spec(s[r1_]).lt()
        assert(post1_self_@[r1_].cmp_spec(post1_self_@[r1_ + 1]).lt());

        // Structure of post2_self_@ = s.insert(r2_, k):
        //   post2_self_@[r1_] == s[r1_]   (since r1_ < r2_)
        //   post2_self_@[r2_] == k
        assert(post2_self_@[r1_] == s[r1_]);
        assert(post2_self_@[r2_] == k);
        assert(0 <= r1_ && r1_ < r2_ && r2_ < post2_self_@.len());
        // Sortedness of post2_self_@ instantiated at (r1_, r2_):
        //   s[r1_].cmp_spec(k).lt()
        assert(post2_self_@[r1_].cmp_spec(post2_self_@[r2_]).lt());

        // Asymmetry: k.cmp_spec(s[r1_]).lt() <==> s[r1_].cmp_spec(k).gt(),
        // and gt vs lt on the same Ordering value are mutually exclusive.
        assert(false);
    } else if r2_ < r1_ {
        // Symmetric.
        assert(post2_self_@[r2_] == k);
        assert(post2_self_@[r2_ + 1] == s[r2_]);
        assert(0 <= r2_ && r2_ + 1 < post2_self_@.len());
        assert(post2_self_@[r2_].cmp_spec(post2_self_@[r2_ + 1]).lt());

        assert(post1_self_@[r2_] == s[r2_]);
        assert(post1_self_@[r1_] == k);
        assert(0 <= r2_ && r2_ < r1_ && r1_ < post1_self_@.len());
        assert(post1_self_@[r2_].cmp_spec(post1_self_@[r1_]).lt());

        assert(false);
    }
}

// With r1 == r2, both views equal pre_self_@.insert(r1_, k), so they are equal
// as sequences (use Seq extensionality to lift to ==).
assert(r1_ == r2_);
assert(post1_self_@ =~= post2_self_@);
assert(post1_self_@ == post2_self_@);
